fn main() -> i64 = {
    let capacity = read_int();
    let n = read_int();

    // Ring buffer implementation using vec and front pointer
    // We use a fixed-size vec of capacity, with front and back pointers
    // Since BMB vecs are dynamic, we'll pre-allocate and use modulo arithmetic
    let buf = vec_new();
    let i = 0;
    while i < capacity {
        let _p = vec_push(buf, 0);
        i += 1
    };

    let mut front = 0;
    let mut back = 0;
    let mut count = 0;

    let op_idx = 0;
    while op_idx < n {
        let op = read_int();
        if op == 1 {
            let val = read_int();
            if count < capacity {
                let _s = vec_set(buf, back, val);
                back = (back + 1) % capacity;
                count = count + 1
            }
            // if full, discard val (no output)
        } else if op == 2 {
            if count > 0 {
                let val = vec_get(buf, front);
                let _p = println(val);
                front = (front + 1) % capacity;
                count = count - 1
            } else {
                let _p = println(-1)
            }
        } else if op == 3 {
            let _p = println(count)
        };
        op_idx += 1
    };

    let _f = vec_free(buf);
    0
};

